(function(){
  const stages=[
    {id:'separation',n:'01',title:'Separation / Immediate problem',sub:'Stabilise urgent practical issues and start a clean evidence trail.',overview:'This stage is about reducing confusion, preserving evidence, and identifying whether urgent court action or practical support is needed.',happens:['Immediate practical arrangements may need attention.','Messages, letters and financial records start to matter.','The key issue is often separating fact, urgency and emotion.'],prepare:['Start a dated chronology.','Save important documents and messages.','Write a one-page issue summary.','List urgent risks or deadlines.'],tasks:['Chronology started','Key documents saved','Urgent issues listed','One-page summary drafted'],bundle:['Chronology','Key correspondence','Financial snapshot','Children arrangements notes'],judge:['Clear dates','Evidence rather than assertion','Practical problem needing decision','Proportionate next step'],confidence:['I can explain the issue in two minutes','I know what evidence supports me','I know the next deadline','My documents are saved']},
    {id:'before-applying',n:'02',title:'Before applying',sub:'Check options, MIAM position, correct application route and evidence.',overview:'Before issuing anything, the focus should be on choosing the correct route and defining the order or outcome being sought.',happens:['Mediation or MIAM may be considered.','The correct form and route must be identified.','Evidence should match the order requested.'],prepare:['Check MIAM or exemption position.','Draft the order or outcome wanted.','Collect supporting documents.','Review whether the issue can be narrowed.'],tasks:['Route checked','MIAM/exemption checked','Draft outcome written','Evidence list prepared'],bundle:['Draft application','MIAM certificate or exemption evidence','Issue summary','Supporting documents'],judge:['Correct application route','Specific order sought','Attempts to resolve','Evidence of urgency if relevant'],confidence:['I know which application is needed','I can explain why court involvement is needed','I have checked alternatives','My evidence list is organised']},
    {id:'application-issued',n:'03',title:'Application issued',sub:'Track service, response deadlines, hearing notice and early documents.',overview:'Once an application is issued, document control becomes important. Keep sealed papers, notices and deadlines together.',happens:['Court issues papers and may list a hearing.','Service and response deadlines may apply.','The court needs the issues to be clear quickly.'],prepare:['Save sealed papers.','Record every deadline.','Create a hearing folder.','Prepare any response in time.'],tasks:['Sealed papers saved','Hearing date recorded','Response deadline noted','Service evidence saved'],bundle:['Sealed application','Hearing notice','Response papers','Service evidence'],judge:['Proper service','Clear response','Identified issues','Urgent directions if needed'],confidence:['I know the next deadline','I know what has been served','I understand what to respond to','I have all court papers']},
    {id:'first-hearing',n:'04',title:'First hearing',sub:'Prepare issues, short position, proposed directions and practical requests.',overview:'The first hearing usually identifies the issues and sets the procedural direction of the case.',happens:['The judge may identify disputed issues.','Directions may be made.','Urgent practical issues may be considered.'],prepare:['Draft a short position statement.','Create a one-page issue list.','Consider proposed directions.','Prepare a concise speaking note.'],tasks:['Position statement drafted','Issue list prepared','Draft directions considered','Speaking note ready'],bundle:['Position statement','Draft directions','Chronology','Key evidence index'],judge:['Disputed issues','Necessary directions','Urgency','What can be agreed'],confidence:['I can state the issues clearly','I know what directions I want','I can find key documents','I have a concise speaking note']},
    {id:'directions',n:'05',title:'Directions and timetable',sub:'Convert the court order into a clear dated task list.',overview:'This stage is about compliance. Every paragraph of the order should become a dated task with proof of completion.',happens:['The court sets deadlines.','Parties exchange documents or statements.','Non-compliance can create delay and risk.'],prepare:['Create a deadline tracker.','Save proof of sending.','Chase missing documents politely.','Keep a correspondence log.'],tasks:['Deadline tracker created','Order converted into tasks','Proof of sending saved','Missing compliance chased'],bundle:['Directions order','Deadline tracker','Correspondence log','Disclosure request list'],judge:['Compliance','Reason for delay','Proportionality','Moving the case forward'],confidence:['Every direction has a task','I know what is overdue','I have proof of sending','I can explain delays factually']},
    {id:'disclosure',n:'06',title:'Disclosure and evidence',sub:'Index documents, identify gaps and connect evidence to issues.',overview:'Disclosure is strongest when it is organised, complete and directly linked to the issues the court must decide.',happens:['Financial or other evidence is exchanged.','Questionnaires or requests may follow.','Missing documents may become disputed.'],prepare:['Index disclosure.','List missing documents.','Create an evidence matrix.','Update the chronology.'],tasks:['Disclosure indexed','Missing documents listed','Evidence matrix started','Chronology updated'],bundle:['Form E','Bank statements','Property evidence','Pension evidence','Witness statements','Bundle index'],judge:['Full and frank disclosure','Documentary proof','Material gaps','Relevance to issues'],confidence:['I know what is missing','I can link evidence to issues','My chronology is updated','I can separate fact from opinion']},
    {id:'negotiation',n:'07',title:'Negotiation and offers',sub:'Compare proposals, implementation and settlement risk.',overview:'Negotiation works best when offers are realistic, evidence-based and capable of being implemented.',happens:['Open and without-prejudice proposals may be exchanged.','Costs and litigation risk may matter.','Settlement depends on practical implementation.'],prepare:['Prepare a settlement comparison.','Separate open and WP material.','Define your acceptable range.','Check net outcomes.'],tasks:['Settlement table prepared','Open/WP letters separated','Costs risk considered','Acceptable range defined'],bundle:['Offer schedule','Asset schedule','Costs schedule','Settlement comparison table'],judge:['Realistic proposals','Implementation','Needs and fairness','Costs risk'],confidence:['I can explain my proposal','I understand the other proposal','I know my minimum outcome','I have considered implementation']},
    {id:'fdr-review',n:'08',title:'FDR / review hearing',sub:'Prepare for judicial indication, settlement and concise submissions.',overview:'The FDR or review stage is settlement-focused. The papers should help the judge understand assets, issues, risk and realistic outcomes.',happens:['The judge reviews papers.','A non-binding indication may be given.','Parties may negotiate around the indication.'],prepare:['Finalise position statement.','Update asset schedule.','Prepare costs schedule.','Practise a short speaking note.'],tasks:['FDR position statement ready','Asset schedule updated','Costs schedule ready','Speaking note prepared'],bundle:['FDR position statement','Chronology','Asset schedule','Costs schedule','Settlement options table'],judge:['Assets','Needs','Settlement realism','Disclosure gaps','Litigation risk'],confidence:['I can explain why my proposal is fair','I know the settlement range','I have key figures ready','I can answer likely questions']},
    {id:'final-hearing',n:'09',title:'Final hearing',sub:'Prepare evidence, cross-examination topics and closing submissions.',overview:'If settlement fails, the court decides disputed issues. Organisation, credibility and bundle references matter.',happens:['Witnesses may give evidence.','Questions may be asked.','The judge considers evidence and submissions.'],prepare:['Finalise evidence matrix.','Prepare cross-examination topics.','Draft closing submissions.','Create a judge bundle guide.'],tasks:['Evidence matrix finalised','Cross-examination topics prepared','Closing submission drafted','Judge bundle guide ready'],bundle:['Final position statement','Evidence matrix','Cross-examination plan','Closing submission','Judge bundle guide'],judge:['Disputed issues','Credibility','Bundle references','Final order sought'],confidence:['I can explain each disputed issue','I know where the evidence is','My questions have a purpose','My closing is structured']},
    {id:'final-order',n:'10',title:'Final order and aftercare',sub:'Implement the order, track compliance and preserve proof.',overview:'The final order must be turned into practical dated actions. Keep proof of compliance and deal with unclear points quickly.',happens:['The order is sealed.','Transfers or payments may be required.','Enforcement or variation may arise if compliance fails.'],prepare:['Create an implementation checklist.','Record deadlines and responsibility.','Save proof of compliance.','Seek advice if unclear.'],tasks:['Sealed order saved','Implementation checklist created','Proof folder ready','Enforcement options understood'],bundle:['Sealed order','Implementation checklist','Payment proof','Transfer records','Correspondence log'],judge:['Clarity','Enforceability','Compliance','Practical implementation'],confidence:['I understand each obligation','I know the deadlines','I know what proof to keep','I know when to get advice']}
  ];
  const $=id=>document.getElementById(id);
  const state={stage:localStorage.getItem('crs-v4-stage')||'separation'};
  const key=(type)=>`crs-v4-${type}-${state.stage}`;
  const arr=(type)=>{try{return JSON.parse(localStorage.getItem(key(type))||'[]')}catch{return []}};
  const save=(type,vals)=>{try{localStorage.setItem(key(type),JSON.stringify(vals))}catch{}};
  const pct=(type,total)=> total?Math.round(arr(type).length/total*100):0;
  function current(){return stages.find(s=>s.id===state.stage)||stages[0]}
  function makeChecks(containerId,type,items,onChange){const c=$(containerId); if(!c) return; const done=arr(type); c.innerHTML=''; items.forEach((item,i)=>{const lab=document.createElement('label'); const input=document.createElement('input'); input.type='checkbox'; input.checked=done.includes(i); const span=document.createElement('span'); span.textContent=item; lab.append(input,span); c.append(lab); input.addEventListener('change',()=>{const vals=[...c.querySelectorAll('input')].map((x,n)=>x.checked?n:null).filter(x=>x!==null); save(type,vals); updateScores(); if(onChange)onChange();});});}
  function list(id,items){const el=$(id); if(!el)return; el.innerHTML=''; items.forEach(x=>{const li=document.createElement('li');li.textContent=x;el.append(li);});}
  function buildIndex(){const s=current(); const done=arr('bundle'); const chosen=s.bundle.filter((_,i)=>done.includes(i)); const use=chosen.length?chosen:s.bundle; return ['COURTREADY BUNDLE INDEX',`Stage ${s.n}: ${s.title}`,'',...use.map((x,i)=>`${i+1}. ${x}`),'','Note: Adapt this index to the court order and bundle directions.'].join('\n');}
  async function copyIndex(){const text=buildIndex(); const out=$('bundle-output-v4'); const status=$('copy-status-v4'); try{await navigator.clipboard.writeText(text); status.textContent='Bundle index copied to clipboard.'; out.hidden=true;}catch(e){out.textContent=text; out.hidden=false; status.textContent='Clipboard access was blocked. The generated index is shown above for manual copy.';}}
  function updateCountdown(){const input=$('hearing-date-v4'), out=$('countdown-v4'); if(!input||!out)return; const v=input.value; if(v) localStorage.setItem('crs-v4-hearing',v); if(!v){out.textContent='No date set.'; return;} const today=new Date(); today.setHours(0,0,0,0); const d=new Date(v+'T00:00:00'); const days=Math.ceil((d-today)/86400000); out.textContent=days<0?`Date passed ${Math.abs(days)} day${Math.abs(days)===1?'':'s'} ago.`:days===0?'Hearing is today.':`${days} day${days===1?'':'s'} remaining.`;}
  function updateScores(){const s=current(); const task=pct('tasks',s.tasks.length), bun=pct('bundle',s.bundle.length), conf=pct('confidence',s.confidence.length); $('task-score').textContent=task+'%'; $('task-fill').style.width=task+'%'; $('bundle-score-v4').textContent=bun+'%'; $('bundle-fill-v4').style.width=bun+'%'; $('confidence-score-v4').textContent=conf+'%'; const overall=Math.round((task+bun+conf)/3); $('overall-score').textContent=overall+'%';}
  function render(){const s=current(); localStorage.setItem('crs-v4-stage',s.id); $('stage-title').textContent=s.title; $('stage-subtitle').textContent=s.sub; $('stage-pill').textContent='Stage '+s.n; $('stage-overview').textContent=s.overview; list('happens-list',s.happens); list('prepare-list',s.prepare); list('judge-list',s.judge); makeChecks('task-list','tasks',s.tasks); makeChecks('bundle-list','bundle',s.bundle); makeChecks('confidence-list','confidence',s.confidence); const ca=$('coach-answer'); if(ca) ca.textContent=''; $('notes-v4').value=localStorage.getItem(key('notes'))||''; document.querySelectorAll('[data-v4-stage]').forEach(b=>b.classList.toggle('active',b.dataset.v4Stage===s.id)); $('stage-select').value=s.id; updateScores();}
  function init(){
    const sel=$('stage-select'), nav=$('stage-nav');
    if(!sel||!nav){ console.error('CourtReady roadmap init failed: stage controls missing'); return; }
    sel.innerHTML=''; nav.innerHTML='';
    stages.forEach(s=>{
      const o=document.createElement('option'); o.value=s.id; o.textContent=`${s.n} — ${s.title}`; sel.append(o);
      const b=document.createElement('button'); b.type='button'; b.dataset.v4Stage=s.id; b.innerHTML=`<span>${s.n}</span><strong>${s.title}</strong>`;
      b.addEventListener('click',()=>{state.stage=s.id;render();}); nav.append(b);
    });
    sel.addEventListener('change',e=>{state.stage=e.target.value;render();});
    const copyBtn=$('copy-index-v4'); if(copyBtn) copyBtn.addEventListener('click',copyIndex);
    const showBtn=$('show-index-v4'); if(showBtn) showBtn.addEventListener('click',()=>{const out=$('bundle-output-v4'); if(out){out.textContent=buildIndex(); out.hidden=!out.hidden;}});
    const h=$('hearing-date-v4'); if(h){ h.value=localStorage.getItem('crs-v4-hearing')||''; h.addEventListener('change',updateCountdown); }
    const notes=$('notes-v4'); if(notes) notes.addEventListener('input',e=>localStorage.setItem(key('notes'),e.target.value));
    updateCountdown(); render();
  }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',init); else init();
})();
